class HashSet:
    def __init__(self, nbuckets=8):
        self.nbuckets = nbuckets
        self.buckets = [[] for _ in range(nbuckets)]

    def _idx(self, k):
        return hash(k) % self.nbuckets

    def add(self, k):
        b = self.buckets[self._idx(k)]
        if k not in b:
            b.append(k)

    def contains(self, k):
        return k in self.buckets[self._idx(k)]

    def remove(self, k):
        b = self.buckets[self._idx(k)]
        if k in b:
            b.remove(k)

