solution:
def longest_unique(s):
    seen = set()
    l = 0
    best = 0
    for r in range(len(s)):
        while s[r] in seen:
            seen.discard(s[l])
            l += 1
        seen.add(s[r])
        if r - l + 1 > best:
            best = r - l + 1
    return best
